from solution import ResourceScope


class Resource:
    def __init__(self, name, log):
        self.name = name
        self.log = log
    def close(self):
        self.log.append(self.name)


def test_closes_reverse_order_on_exception():
    log = []
    try:
        with ResourceScope() as scope:
            scope.acquire(Resource('first', log))
            scope.acquire(Resource('second', log))
            raise RuntimeError('boom')
    except RuntimeError:
        pass
    assert log == ['second', 'first']
